import{_ as i,o as t,c as o,ag as l}from"./chunks/framework.eQLvDOR_.js";const p=JSON.parse('{"title":"linguistic-code-complexity","description":"","frontmatter":{"title":"linguistic-code-complexity","concept":"语言学代码复杂度","concept_id":"linguistic-code-complexity","aliases":["MDD","DLT","Cognitive-Load-for-AI"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] How Complex is my Code.md"],"related_concepts":["[[context-optimization]]","[[claude-code-agent-os]]"],"created_at":"2026-04-21","last_compiled":"2026-04-21"},"headers":[],"relativePath":"wiki/concepts/linguistic-code-complexity.md","filePath":"wiki/concepts/linguistic-code-complexity.md","lastUpdated":null}'),a={name:"wiki/concepts/linguistic-code-complexity.md"};function c(n,e,r,s,d,u){return t(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="语言学代码复杂度-linguistic-code-complexity" tabindex="-1">语言学代码复杂度 (Linguistic Code Complexity) <a class="header-anchor" href="#语言学代码复杂度-linguistic-code-complexity" aria-label="Permalink to &quot;语言学代码复杂度 (Linguistic Code Complexity)&quot;">​</a></h1><h2 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h2><p>超越传统的圈复杂度（Cyclomatic Complexity），从认知科学和心理语言学的视角评估：<strong>代码对“人”和“AI”理解的难易程度。</strong></p><h2 id="核心指标" tabindex="-1">核心指标 <a class="header-anchor" href="#核心指标" aria-label="Permalink to &quot;核心指标&quot;">​</a></h2><ol><li><strong>平均依赖距离 (Mean Dependency Distance, MDD)</strong>: <ul><li>定义：变量定义与其使用位置之间的物理行数距离。</li><li>对 AI 的影响：距离越远，KV Cache 中的注意力压力越大，容易产生上下文衰减。</li></ul></li><li><strong>依赖局部性理论 (Dependency Locality Theory, DLT)</strong>: <ul><li>定义：在解析句子（或代码）时，需要在工作记忆中同时保持的“未闭合依赖”数量。</li><li>对 AI 的影响：过高的 DLT（如深层嵌套、超长函数 fan-out）会导致 AI 在生成过程中更容易产生“概念漂移”。</li></ul></li><li><strong>类型/词符比 (Type-Token Ratio)</strong>: <ul><li>定义：唯一单词数与总单词数的比值（接近 Halstead 复杂度）。</li><li>反映：代码库的“概念密度”。</li></ul></li></ol><h2 id="ai-友好型代码原则" tabindex="-1">AI 友好型代码原则 <a class="header-anchor" href="#ai-友好型代码原则" aria-label="Permalink to &quot;AI 友好型代码原则&quot;">​</a></h2><ul><li><strong>窄作用域</strong>：降低 MDD。</li><li><strong>扁平化结构</strong>：降低 DLT。</li><li><strong>高可预测性 (Low Entropy)</strong>：减少意外的代码设计。AI 在处理低熵（高预测性）代码时，Token 预测的置信度更高，生成的逻辑准确度也更高。</li></ul><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>重构策略</strong>：不仅要通过圈复杂度找 Bug，更要通过可视化 MDD（依赖连线）找到那些导致 AI 推理变慢的“长程依赖”代码。</li><li><strong>AI 辅助评估</strong>：使用 <code>/inspect</code> 命令配合自定义提示词，让 AI 根据 MDD 和 DLT 为模块打分。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - How Complex is my Code.html">[Agent_Architecture] How Complex is my Code</a></li></ul>',13)])])}const g=i(a,[["render",c]]);export{p as __pageData,g as default};
